import{_ as a,o as t,c as i,ag as r}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"QiAccess Start Legacy Quarantine","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/60_knowledge/60_qiaccess_start_legacy_quarantine.md","filePath":"10_core/60_knowledge/60_qiaccess_start_legacy_quarantine.md"}'),n={name:"10_core/60_knowledge/60_qiaccess_start_legacy_quarantine.md"};function l(o,e,s,c,d,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="qiaccess-start-legacy-quarantine" tabindex="-1">QiAccess Start Legacy Quarantine <a class="header-anchor" href="#qiaccess-start-legacy-quarantine" aria-label="Permalink to &quot;QiAccess Start Legacy Quarantine&quot;">​</a></h1><p>This appendix marks the legacy doctrine that is retained for reference but is not active truth for the current QiAccess Start master blueprint.</p><h2 id="active-doctrine" tabindex="-1">Active Doctrine <a class="header-anchor" href="#active-doctrine" aria-label="Permalink to &quot;Active Doctrine&quot;">​</a></h2><p>The active portal doctrine is:</p><ul><li>QiAccess Start as the cognitive front door</li><li>seven roots only</li><li>System as nested admin and infrastructure</li><li>qiserver as the primary runtime host</li><li>QiNexus and Google Drive as the storage backbone</li><li>source-backed Knowledge, future Memory, and derived Insights</li></ul><h2 id="what-is-quarantined" tabindex="-1">What Is Quarantined <a class="header-anchor" href="#what-is-quarantined" aria-label="Permalink to &quot;What Is Quarantined&quot;">​</a></h2><p>The following assumptions are quarantined unless explicitly revalidated:</p><ul><li>QiOne as the active primary portal identity</li><li>QiPortals or QiSuite as the active portal product name</li><li>multi-tenant client portal language as the default runtime model</li><li>tenant-first platform requirements for current operator workflows</li><li>CRM, client, product, and delivery documentation treated as the main active operating model</li><li>heavy structural complexity that does not directly serve the seven-root front door</li></ul><h2 id="quarantined-areas-in-this-docset" tabindex="-1">Quarantined Areas In This Docset <a class="header-anchor" href="#quarantined-areas-in-this-docset" aria-label="Permalink to &quot;Quarantined Areas In This Docset&quot;">​</a></h2><p>These sections are retained because they may still contain useful fragments, but they must be treated as reference-only until rewritten:</p><ul><li><code>docs/06_applications/10_web/</code></li><li><code>docs/06_applications/30_admin/</code></li><li><code>docs/06_applications/40_tools/</code></li><li><code>docs/06_applications/50_interfaces/</code></li><li><code>docs/07_operations/</code></li><li>pages that still depend on tenant-first or client-platform assumptions</li></ul><h2 id="what-survives-from-legacy" tabindex="-1">What Survives From Legacy <a class="header-anchor" href="#what-survives-from-legacy" aria-label="Permalink to &quot;What Survives From Legacy&quot;">​</a></h2><p>Legacy material may still provide:</p><ul><li>naming discipline</li><li>metadata rules</li><li>explicit ownership boundaries</li><li>ADR discipline</li><li>security and exposure controls</li><li>useful implementation notes that do not conflict with the current portal</li></ul><h2 id="promotion-rule" tabindex="-1">Promotion Rule <a class="header-anchor" href="#promotion-rule" aria-label="Permalink to &quot;Promotion Rule&quot;">​</a></h2><p>Legacy material leaves quarantine only when one of the following happens:</p><ol><li>it is rewritten to match the active QiAccess Start doctrine</li><li>an ADR explicitly promotes the concept back into active use</li><li>the implementation proves the concept is current and the blueprint is updated to match</li></ol><h2 id="general-rule" tabindex="-1">General Rule <a class="header-anchor" href="#general-rule" aria-label="Permalink to &quot;General Rule&quot;">​</a></h2><ul><li>Legacy client/tenant/business-platform doctrine must stay quarantined/reference-only.</li></ul>',19)])])}const m=a(n,[["render",l]]);export{p as __pageData,m as default};
